var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":null,"text":{"KOREA":" 따끈따끈한 소식이야, 블랙 네트워크 친구들.","JPN":" アツアツのニュースだよ、ブラックネットワークのみんな。","ENG":"I have some juicy news, my fellow Dark Network members.","TWN":"各位黑色網路的網友們，告訴大家一個最新消息！"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_BEEP"},{"id":"L3_1","type":"dialog","speaker":null,"text":{"KOREA":" 내 친구가 관리국에서 일하는데, 고심도 좌표에서 어떤 미친놈들이 다른 태스크포스들을 습격하는 것 같아.","JPN":" 私の友達が管理局で働いてるんだけど、高深度の座標でイカれた奴らが他のタスクフォースを襲撃してるみたい。","ENG":"I have a friend that works at the Administration, and it seems that some crazy goons are attacking another TASKFORCE at some hyperdepth coordinates.","TWN":"我朋友在管理局做事，據說在高深度座標有群瘋子突襲其他特遣勢力欸！"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":null,"text":{"KOREA":" ┕ 스캐빈저다. 그놈들 결국 저질렀군.","JPN":" ┕ スカベンジャーだ。あいつら結局やらかしたな。","ENG":"┕ It’s the Scavengers. So, they’ve thrown the dice.","TWN":" ┕ 是清道夫幹的，他們終究還是幹下這種壞事。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_BEEP"},{"id":"L5_1","type":"dialog","speaker":null,"text":{"KOREA":" ┕ 저질렀군이랜다ㅋㅋㅋ 너 때문에 웃으면서 출근함.","JPN":" ┕ やらかしたな、だってｗｗｗ　お前のおかげで出勤中笑ったよ。","ENG":"┕ \\"Thrown the dice\\" LOL. I’m starting my day with a good laugh thanks to you. Haha!","TWN":" ┕ 壞人不幹壞事幹什麼，ㄎㄎㄎ 被你笑死。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_BEEP"},{"id":"L6_1","type":"dialog","speaker":null,"text":{"KOREA":" ┕ 세상의 멸망이 다가왔습니다! 회개하십시오!","JPN":" ┕ 世界の滅亡が近づいてきました！　悔い改めなさい！","ENG":"┕ The end of the world has come! Repent!","TWN":" ┕ 世界末日即將到來，趕快悔改！"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_BEEP"},{"id":"L7_1","type":"dialog","speaker":null,"text":{"KOREA":" ┕ 아니 근데 진짜면 좀 심각한 거 아님? 왜 공문 하나 안 오냐?","JPN":" ┕ いや、でも本当ならマジやばくね？　なんで公文書とか送られてこないの？","ENG":"┕ No, but on a serious note, isn’t this a big deal? Why aren’t there any announcements?","TWN":" ┕ 如果是真的，那事情這麼大條怎麼都沒收到公文？"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_BEEP"},{"id":"L8_1","type":"dialog","speaker":null,"text":{"KOREA":" ┕ 멸망이고 나발이고 난 오늘 휴가 짤려서 채굴 나감. 수구.","JPN":" ┕ 滅亡も何も、俺は今日有給拒否されて採掘に行くよ。乙。","ENG":"┕ Who cares about the end of the world? My leave request got denied, so I’m off to the mines. Smell ya later","TWN":" ┕ 管他是末日還是胡說八道，我只知道我今天休假被取消要去開採，哭哭。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_BEEP"},{"id":"L11_1","type":"dialog","speaker":null,"text":{"KOREA":" 반복한다! 이 구조 요청은 관리국이 지정한 단파 회선을 통해 송신 중이다!","JPN":" 繰り返す！　この救助要請は管理局が指定した短波回線から送信している！","ENG":"I repeat! This is a mayday broadcast on the Administration-designated shortwave line!","TWN":"再重複一次！這個求救訊號是透過管理局指定的短波天線傳送的！"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L12_1","type":"dialog","speaker":null,"text":{"KOREA":" 현재 우리는 심도 4에서 채굴 중에 철갑옷을 입은 기사들에게 공격 받고 있다!","JPN":" 現在我々は深度4での採掘作業中、鉄の鎧を着た騎士たちに攻撃されている！","ENG":"We were attacked by armored knights while mining in Depth 4 and are pinned down!","TWN":"我們在深度4開採途中受到身穿鎧甲的騎士攻擊！"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L13_1","type":"dialog","speaker":null,"text":{"KOREA":" 스캐빈저든 누구든 좋아! 이 무전을 듣는다면 도움을──","JPN":" スカベンジャーでも誰でもいい！　この通信を聞いたら助けを――","ENG":"Whether it be Scavengers or whoever, if you can hear this broadcast, please help─","TWN":"清道夫也好，誰都好！聽到這個無線電請來支──"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L19_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"……클리포트 게임?","JPN":"……クリフォトゲーム？","ENG":"...Qliphoth Game?","TWN":"……逆卡巴拉遊戲？"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"그렇습니다. 구 관리국은 본래 클리포트 게임을 저지하기 위해 결성된 조직이니까요.","JPN":"そうです。旧管理局は本来、クリフォトゲームを阻止するために結成された組織ですから。","ENG":"That’s correct. The Old Administration was originally established to prevent the Qliphoth Game.","TWN":"沒錯，舊管理局原本就是為阻止逆卡巴拉遊戲而成立的組織。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"당신이 구 관리국의 올드 카운터 출신이라는 것도 그렇고……","JPN":"君が旧管理局のオールドカウンター出身だというのもそうだが……","ENG":"Including the fact that you were an Old Counter from the Old Administration...","TWN":"你是從舊管理局時期就存在的制裁者嗎……"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"오늘은 하나같이 놀랄 만한 일들뿐이군.","JPN":"今日はすべて驚かされることばかりだな。","ENG":"Today is simply full of surprises.","TWN":"包括這件事在內，今天淨是些令人驚訝的事呢。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"당신 말대로라면 그 허신이라는 괴물도 클리포트 게임의 전조에 불과하다는 건가?","JPN":"君のいうとおりなら、あの虚神という化け物もクリフォトゲームの前兆に過ぎないということか？","ENG":"So, if we assume that what you’re saying is correct, the monster called \\"Hollow God\\" is merely harbingers of the Qliphoth Game?","TWN":"若照你所說，那個叫作幻神的怪物，不過就是逆卡巴拉遊戲的序幕而已嗎？"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"정확한 표현은 아닙니다만…… 비슷합니다.","JPN":"正しい表現ではありませんが……似たようなものです。","ENG":"Although not a completely accurate description, it’s close enough.","TWN":"這個說法不太準確……但類似這樣沒錯。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"허신은 분명 강력한 존재입니다.","JPN":"虚神は確かに強力な存在です。","ENG":"The Hollow Gods are powerful beings, no doubt about that.","TWN":"幻神的威力不容小覷。"},"stage":{"bg":"MAINSTREAM_808","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L27_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"하지만 결국 클리포트 게임을 열기 위한 조건들 중 하나일 뿐이죠.","JPN":"ですが、結局はクリフォトゲームを始めるための条件の一つに過ぎません。","ENG":"However, it's merely one of the prerequisites for starting the Qliphoth Game.","TWN":"不過說到底也只是開啟逆卡巴拉遊戲的條件之一而已。"},"stage":{"bg":"MAINSTREAM_808","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L28_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"MAINSTREAM_808","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L31_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"그럼 그 마왕……. 신성 침식체라는 자들이 게임에 참가하는 건가?","JPN":"それではあの魔王……神聖侵食体とやらがゲームに参加するのか？","ENG":"Then, the Demon Lords... Those so-called \\"Divine Corrupted Objects\\" participate in this game?","TWN":"那魔王……那些稱為神聖侵蝕體的傢伙也會參與遊戲嗎？"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"거칠게 요약하면 그렇습니다.","JPN":"ざっくり言うとそうなります。","ENG":"To roughly summarize, yes.","TWN":"是可以這麼說。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"물론 패배의 대가는 이 세상의 종말이겠죠.","JPN":"もちろん敗北の代価はこの世界の終わりでしょう。","ENG":"Of course, the price of losing the game would be the end of this world.","TWN":"不過，失敗的代價就是這個世界會滅亡。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"맙소사, 내가 판타지 소설의 줄거리를 듣고 있는 게 아닌지 의심스럽군.","JPN":"は、私はファンタジー小説のあらすじを聞いているんじゃないだろうな？","ENG":"My goodness, part of me wonders if I am listening to the plot of a fantasy novel.","TWN":"我的天，我懷疑我現在是在聽科幻小說的劇情嗎？"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"마왕과 세상을 걸고 게임을 벌인다니…….","JPN":"魔王と世界をかけてゲームするとは……","ENG":"Playing a game against Demon Lords with the fate of the world at stake...","TWN":"賭上魔王和世界啟動遊戲……"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"이해합니다. 저도 처음에는 질 나쁜 농담인줄 알았거든요.","JPN":"わかります。私も最初は質の悪い冗談かと思いましたから。","ENG":"I understand that you’re overwhelmed. I also thought it was an extremely tasteless joke at first.","TWN":"我懂你的心情，我一開始聽到時也以為是很不好笑的笑話。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"어쨌거나 저희는 클리포트 게임이 다시 시작되는 걸 막기 위해 노력해 왔습니다.","JPN":"とにかく、私たちはクリフォトゲームが再び始まることを止めるために頑張ってきました。","ENG":"Anyway, we have been working to prevent the Qliphoth Game from starting again.","TWN":"總之，我們一直努力不讓逆卡巴拉遊戲重啟。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"그리고 지금처럼 그 노력이 물거품으로 돌아갈 경우…….","JPN":"そして今のようにその努力が水の泡となる場合に備え……","ENG":"And should our efforts go to waste like in our current situation...","TWN":"另一方面，我們也一直有在準備，若是我們的努力像現在這樣化作泡沫時……"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"게임에서 승리하기 위한 준비를 진행해 왔죠.","JPN":"ゲームで勝利するための準備をしてきました。","ENG":"We have been preparing to ensure our victory in the game.","TWN":"我們要如何在遊戲中取勝。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"아주 오랫동안, 일반인들은 이해 못할 다양한 방식으로 가능성들을 만들면서 말입니다.","JPN":"とても長い間、一般人には理解できないような様々な方法で可能性を作りながら、です。","ENG":"For a long time, we have been creating countless possibilities using various methods that ordinary people would not be able to understand.","TWN":"有很長一段時間，我們都在思考著一般人無法理解的各樣可能性。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"그래서, 승산이 있다는 건가?","JPN":"それで、勝ち目はあるのか？","ENG":"So, are you saying that we have a shot at winning?","TWN":"意思是，有勝算？"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"……글쎄요. 전 이미 한 번 패배한 입장이라.","JPN":"……どうでしょう。私は一度負けましたので。","ENG":"...I can’t say for sure. I’ve already lost once before.","TWN":"……這個嘛，畢竟我已經失敗過一次，"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"제 고용주의 준비가 충분하기만을 기대할 뿐입니다.","JPN":"私の雇い主の準備が十分であることに期待するだけです。","ENG":"I can only hope that my employer has made sufficient preparations.","TWN":"因此我也只能期待我的老闆有充分的準備。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"상황은 이해했네. 하지만 당신 이야기를 들으니 의문이 생기는군.","JPN":"状況は理解した。だが君の話を聞くと疑問が生じるな。","ENG":"I understand the situation. However, after listening to your story, I have my doubts.","TWN":"情況我已經大致理解，不過我有些疑問。"},"stage":{"bg":"QLIPHOTH","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L47_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"그동안 당신을 비롯한 구 관리국의 생존자들은 정체를 숨기고 활동했지.","JPN":"今まで君を始め、旧管理局の生き残りたちは正体を隠して活動してきた。","ENG":"All this time, survivors of the Old Administration, including yourself, have been active while keeping their identities a secret.","TWN":"過去這段時間，包括你在內的舊管理局倖存者，都是隱藏身分在行動的吧。"},"stage":{"bg":"QLIPHOTH","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L48_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"누구의 감시도, 책임도 지지 않은 채. 자신들만의 정의를 위해서.","JPN":"誰かに監視されることも、責任を取ることもなく。自分たちだけの正義のために。","ENG":"All without any monitoring or responsibility. All to carry out their own forms of justice.","TWN":"沒有受到任何人的監視，也不需要負任何責任，單單為你們所謂的正義，"},"stage":{"bg":"QLIPHOTH","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L49_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"그리고 자신들의 거대한 계획에 휘말린 피해자들에 대해서도 아랑곳하지 않았어.","JPN":"そして自分たちの巨大な計画に巻き込まれる被害者も気にかけなかった。","ENG":"In the meantime, no thought was given to the victims that were caught in the crossfire of their grand scheme as collateral damage.","TWN":"也不理會那些捲入你們偉大計劃的受害者。"},"stage":{"bg":"QLIPHOTH","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L50_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"예를 들어, 한때 내 전우였던 충성스런 부관이라거나.","JPN":"例えば、かつて私の戦友だった忠義な副官だとかな。","ENG":"For example, my once loyal aide, who was also my former comrade.","TWN":"像是我曾經的好戰友，也非常忠心的副司令。"},"stage":{"bg":"QLIPHOTH","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"……","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"말해 보게. 이제 와서 내게 이런 이야기를 하는 이유가 뭐지?","JPN":"言ってみろ。今更私にこんな話をする理由は何だ？","ENG":"Tell me, why are you telling me all of this now?","TWN":"說吧，為什麼你現在要跟我說這些？"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"두렵기 때문입니다.","JPN":"恐ろしいからです。","ENG":"Because I’m afraid.","TWN":"因為害怕。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"뭐라고?","JPN":"なんだと？","ENG":"What?","TWN":"什麼？"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"다시 말씀드리지만, 구 관리국은 클리포트 게임에 대응하기 위해 세워졌던 조직입니다.","JPN":"もう一度言いますが、旧管理局はクリフォトゲームに対応するために立ち上げられた組織です。","ENG":"As I mentioned before, the Old Administration was established as a countermeasure to the Qliphoth Game.","TWN":"我再說一次，舊管理局是為應付逆卡巴拉遊戲而設立的組織。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"자랑은 아니지만 저는 그 중에서도 가장 강한 자들 중 하나였죠.","JPN":"自慢ではありませんが、私はその中でも一二を争う強さでした。","ENG":"Not to brag, but I was considered one of the strongest even within that organization.","TWN":"我不是在老王賣瓜，我好歹也是組織中最強的前幾名。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"그런 저희가 지금까지 몇 명의 마왕을 쓰러트렸는지 아십니까?","JPN":"そんな私たちが今まで魔王を何人倒してきたがご存じですか？","ENG":"Do you know how many Demon Lords we managed to defeat?","TWN":"但你知道我們這些所謂的強者，至今打敗過幾個魔王嗎？"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"……몇 명인가?","JPN":"……何人だ？","ENG":"...How many?","TWN":"……幾個？"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"단 한 명도 쓰러트리지 못했습니다.","JPN":"一人も倒せなかったんです。","ENG":"Not a single one.","TWN":"一個都沒有。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"……","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"그저 게임이 열리는 것을 막거나 룰에 따라 저지했을 뿐이죠.","JPN":"ただゲームが始まるのを止めるか、ルールに従い阻止しただけです。","ENG":"All we could do was prevent the game from starting, or follow the rules to stop it.","TWN":"我們頂多就是阻止遊戲啟動，或是照規則進行妨礙而已。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"마지막은…… 그것마저도 실패했고요.","JPN":"最後は……それさえ失敗しました。","ENG":"And during the last game... we failed to do even that in the end.","TWN":"結果……連這件事也失敗收場。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"저는 제 고용주의 준비가 충분하길 바랍니다.","JPN":"私は自分の雇い主の準備が十分であることを願っています。","ENG":"I can only hope that my employer’s preparations will be enough.","TWN":"我希望我老闆有萬全的準備，"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"하지만 한편으로는 그러지 못할까 봐 두렵습니다.","JPN":"しかし、一方ではそれが不可能なのではないかと恐れています。","ENG":"However, a part of me is afraid that they will not be enough.","TWN":"但另一方面，我也害怕還是會失敗。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"그러니 도움이 필요합니다.","JPN":"ですので、助けが必要です。","ENG":"That is why we need your help.","TWN":"因此我們需要幫助。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"허신을 쓰러트린 당신들이라면, 충분히 도움이 되겠죠.","JPN":"虚神を倒したあなたたちなら、助っ人としては十分でしょう。","ENG":"Considering that you were able to defeat the Hollow God, your help will be invaluable.","TWN":"而你們曾經打敗過幻神，我相信你們一定可以幫上忙。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"이제 의문이 해결되셨습니까?","JPN":"答えになったでしょうか。","ENG":"Does that address your doubts?","TWN":"這樣有替你解惑嗎？"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"……묻고 싶은 건 아직 한참 남았지만, 지금은 그럴 때가 아닌 것 같군.","JPN":"……聞きたいことは山ほどあるが、今はそれどころではなさそうだな。","ENG":"...I still have a mountain of questions that I would like to ask, but now is not the time.","TWN":"……我還有一堆問題想問，但現在似乎不是問問題的好時機。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"내가 할 수 있는 최선을 다해서 준비하도록 하겠네.","JPN":"私にできる最善を尽くして準備しよう。","ENG":"I will prepare the best as I can.","TWN":"我會盡我所能地做好準備！"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"아. 그러고 보니 가장 중요한 내용을 듣는다는 걸 잊고 있었군.","JPN":"あ。そういえば一番重要なことを聞き忘れたな。","ENG":"Ah, thinking about it, I forgot to ask the most important thing.","TWN":"對了，差點忘記還有一個最重要的問題。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"그 클리포트 게임이라는 건…… 언제 시작되는 거지?","JPN":"そのクリフォトゲームってのは……いつ始まるんだ？","ENG":"This Qliphoth Game... When does it start?","TWN":"那個逆卡巴拉遊戲……什麼時候開始？"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"이미 시작되었습니다.","JPN":"すでに始まっています。","ENG":"It has already begun.","TWN":"已經開始了。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}}]`);export{e as default};